# Utility helpers
# ─────────────────────────────────────────────
def clamp(v, lo, hi):
    return max(lo, min(hi, v))

def lerp(a, b, t):
    return a + (b - a) * clamp(t, 0.0, 1.0)

def hsv_to_rgb(h, s, v):
    h = h % 1.0
    i = int(h * 6)
    f = h * 6 - i
    p = v * (1 - s)
    q = v * (1 - f * s)
    t = v * (1 - (1 - f) * s)
    r, g, b = [(v, t, p), (q, v, p), (p, v, t),
               (p, q, v), (t, p, v), (v, p, q)][i % 6]
    return (int(r * 255), int(g * 255), int(b * 255))

def alpha_surface(w, h):
    s = pygame.Surface((w, h), pygame.SRCALPHA)
    s.fill((0, 0, 0, 0))
    return s

def draw_circle_clip(surface, center, radius):
    """Return a surface clipped to a circle."""
    mask = alpha_surface(surface.get_width(), surface.get_height())
    pygame.draw.circle(mask, (255, 255, 255, 255), center, radius)
    surface.blit(mask, (0, 0), special_flags=pygame.BLEND_RGBA_MIN)

def glow_circle(surf, cx, cy, r, color, alpha=80):
    for i in range(4, 0, -1):
        s = alpha_surface(surf.get_width(), surf.get_height())
        c = (*color[:3], alpha // i)
        pygame.draw.circle(s, c, (cx, cy), r + i * 4)
        surf.blit(s, (0, 0))

