    def update(self, dt, amp):
        super().update(dt, amp)
        self.rotation_speed = lerp(self.rotation_speed, 0.5 + amp * 1.5, dt * 3)
        for i in range(len(self.rung_brightness)):
            phase = self.t * 3 + i * 0.3
            if math.sin(phase) > 0.7 and amp > 0.2:
                self.rung_brightness[i] = min(1.0, self.rung_brightness[i] + amp * 0.5)
            else:
                self.rung_brightness[i] *= 0.93

    def draw(self, screen):
        surf = alpha_surface(self.radius * 2 + 10, self.radius * 2 + 10)
        ox, oy = self.cx - self.radius - 5, self.cy - self.radius - 5
        lx, ly = self.radius + 5, self.radius + 5

        pygame.draw.circle(surf, (5, 5, 20), (lx, ly), self.radius)

        num_rungs = 20
        helix_height = self.radius * 1.8
        strand_width = max(2, int(4 + self.amp * 3))
        perspective_scale = 0.4

        angle_offset = self.t * self.rotation_speed

        for i in range(num_rungs):
            frac = i / (num_rungs - 1)
            y = ly - self.radius * 0.9 + frac * helix_height
            angle = frac * math.pi * 4 + angle_offset

            x1 = lx + math.cos(angle) * self.radius * 0.55
            x2 = lx + math.cos(angle + math.pi) * self.radius * 0.55
            depth1 = math.sin(angle)
            depth2 = math.sin(angle + math.pi)

            # Strand 1 (cyan-blue)
            bright1 = (depth1 + 1) / 2
            c1 = (int(0 * bright1 + 0 * (1 - bright1)),
                  int(255 * bright1 + 50 * (1 - bright1)),
                  int(255 * bright1 + 255 * (1 - bright1)))
            pygame.draw.circle(surf, c1, (int(x1), int(y)), strand_width)

            # Strand 2 (magenta-violet)
            bright2 = (depth2 + 1) / 2
            c2 = (int(255 * bright2 + 100 * (1 - bright2)),
                  int(0 * bright2),
                  int(204 * bright2 + 255 * (1 - bright2)))
            pygame.draw.circle(surf, c2, (int(x2), int(y)), strand_width)

            # Rung
            rb = self.rung_brightness[i]
            rung_alpha = int(60 + rb * 195)
            rung_width = max(1, int(2 + rb * 6))
            rs = alpha_surface(self.radius * 2 + 10, self.radius * 2 + 10)
            pygame.draw.line(rs, (255, 255, 255, rung_alpha),
                             (int(x1), int(y)), (int(x2), int(y)), rung_width)
            surf.blit(rs, (0, 0))

        # Connect strands with curves
        for i in range(num_rungs - 1):
            frac1 = i / (num_rungs - 1)
            frac2 = (i + 1) / (num_rungs - 1)
            y1 = ly - self.radius * 0.9 + frac1 * helix_height
            y2 = ly - self.radius * 0.9 + frac2 * helix_height
            a1 = frac1 * math.pi * 4 + angle_offset
            a2 = frac2 * math.pi * 4 + angle_offset
            x1a = lx + math.cos(a1) * self.radius * 0.55
            x2a = lx + math.cos(a2) * self.radius * 0.55
            x1b = lx + math.cos(a1 + math.pi) * self.radius * 0.55
            x2b = lx + math.cos(a2 + math.pi) * self.radius * 0.55
            d1 = (math.sin(a1) + 1) / 2
            d2 = (math.sin(a2) + 1) / 2
            c1 = (int(d1 * 0), int(d1 * 255), int(d1 * 255 + (1 - d1) * 51))
            c2 = (int(d1 * 255), 0, int(d1 * 204 + (1 - d1) * 255))
            pygame.draw.line(surf, c1, (int(x1a), int(y1)), (int(x2a), int(y2)), max(1, strand_width - 1))
            pygame.draw.line(surf, c2, (int(x1b), int(y1)), (int(x2b), int(y2)), max(1, strand_width - 1))

        # Clip
        mask = alpha_surface(self.radius * 2 + 10, self.radius * 2 + 10)
        pygame.draw.circle(mask, (255, 255, 255, 255), (lx, ly), self.radius)
        surf.blit(mask, (0, 0), special_flags=pygame.BLEND_RGBA_MIN)
        screen.blit(surf, (ox, oy))
        self.draw_border(screen)

