# ─────────────────────────────────────────────
COLS = 4
ROWS = 2
PAD_X = (WIDTH - COLS * (AVATAR_RADIUS * 2 + 20)) // (COLS + 1)
PAD_Y = 60
CELL_W = AVATAR_RADIUS * 2 + 20
CELL_H = AVATAR_RADIUS * 2 + 40

positions = []
for row in range(ROWS):
    for col in range(COLS):
        cx = PAD_X + col * (CELL_W + PAD_X) + AVATAR_RADIUS + 10
        cy = PAD_Y + row * (CELL_H + 30) + AVATAR_RADIUS + 20
        positions.append((cx, cy))

avatars = [
    AuroraVeil(positions[0][0], positions[0][1], AVATAR_RADIUS),
    CrystalGeode(positions[1][0], positions[1][1], AVATAR_RADIUS),
    PhantomFlame(positions[2][0], positions[2][1], AVATAR_RADIUS),
    DNAHelix(positions[3][0], positions[3][1], AVATAR_RADIUS),
    VortexEye(positions[4][0], positions[4][1], AVATAR_RADIUS),
    TeslaCoil(positions[5][0], positions[5][1], AVATAR_RADIUS),
    RingedPlanet(positions[6][0], positions[6][1], AVATAR_RADIUS),
    BloomMandala(positions[7][0], positions[7][1], AVATAR_RADIUS),
]

font_small = pygame.font.SysFont("Arial", 11, bold=False)
font_title = pygame.font.SysFont("Arial", 18, bold=True)

print("AvatarEcho — 8 Avatars running. Press ESC or close window to quit.")
print("Audio is simulated with random beat pulses.")

# ─────────────────────────────────────────────
# Main loop
# ─────────────────────────────────────────────
running = True
last_time = time.time()

while running:
    now = time.time()
    dt = min(now - last_time, 0.05)
    last_time = now

    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            running = False
        if event.type == pygame.KEYDOWN and event.key == pygame.K_ESCAPE:
            running = False

    amp = audio_sim.update(dt)

    screen.fill((8, 8, 18))

    # Title
    title = font_title.render("AvatarEcho  —  Expanded Avatar Creative Brief", True, (180, 180, 220))
    screen.blit(title, (WIDTH // 2 - title.get_width() // 2, 8))

    # Amplitude bar
    bar_w = int(amp * 200)
    pygame.draw.rect(screen, (40, 40, 60), (WIDTH // 2 - 100, HEIGHT - 22, 200, 10), 1)
    pygame.draw.rect(screen, (100, 200, 255), (WIDTH // 2 - 100, HEIGHT - 22, bar_w, 10))
    amp_label = font_small.render(f"Amplitude: {amp:.2f}", True, (150, 150, 180))
    screen.blit(amp_label, (WIDTH // 2 - amp_label.get_width() // 2, HEIGHT - 38))

    for av in avatars:
        av.update(dt, amp)
        av.draw(screen)
        av.draw_label(screen, font_small)

    pygame.display.flip()
    clock.tick(FPS)

pygame.quit()
sys.exit()